INSERT INTO `pcta_options` VALUES (173,'widget_black-studio-tinymce','a:6:{i:2;a:5:{s:5:\"title\";s:12:\"Información\";s:4:\"text\";s:746:\"<table style=\"border-collapse: collapse; width: 100%; height: 96px;\">\r\n<tbody>\r\n<tr style=\"height: 24px;\">\r\n<td style=\"width: 46.134%; height: 24px;\">[icon name=\"phone\" class=\"\" unprefixed_class=\"\"]</td>\r\n<td style=\"width: 53.866%; height: 24px;\">+51 914 248 899</td>\r\n</tr>\r\n<tr style=\"height: 24px;\">\r\n<td style=\"width: 46.134%; height: 24px;\">[icon name=\"envelope\" class=\"\" unprefixed_class=\"\"]</td>\r\n<td style=\"width: 53.866%; height: 24px;\">info@peruconexiontravel.com\r\nreservas:@peruconexiontravel.com</td>\r\n</tr>\r\n<tr style=\"height: 48px;\">\r\n<td style=\"width: 46.134%; height: 48px;\">[icon name=\"map-marker\" class=\"\" unprefixed_class=\"\"]</td>\r\n<td style=\"width: 53.866%; height: 48px;\">APV. Sol Naciente M-1</td>\r\n</tr>\r\n</tbody>\r\n</table>\";s:4:\"type\";s:6:\"visual\";s:6:\"filter\";s:1:\"1\";s:8:\"zigclass\";s:17:\"Box-2-Informacion\";}i:3;a:5:{s:5:\"title\";s:8:\"Horarios\";s:4:\"text\";s:121:\"[icon name=\"clock-o\" class=\"\" unprefixed_class=\"\"]  horario de atencion:\r\nLunes a Domingos: 24 horas\r\n\r\n&nbsp;\r\n\r\n&nbsp;\";s:4:\"type\";s:6:\"visual\";s:6:\"filter\";s:1:\"1\";s:8:\"zigclass\";s:14:\"Box-2-horarios\";}i:4;a:5:{s:5:\"title\";s:0:\"\";s:4:\"text\";s:303:\"<a href=\"#\">[icon name=\"facebook-square\" class=\"\" unprefixed_class=\"\"]</a>    <a href=\"#\">[icon name=\"twitter-square\" class=\"\" unprefixed_class=\"\"]</a>    <a href=\"#\">[icon name=\"instagram\" class=\"\" unprefixed_class=\"\"] </a>   <a href=\"#\">[icon name=\"tripadvisor\" class=\"\" unprefixed_class=\"\"]</a>\";s:4:\"type\";s:6:\"visual\";s:6:\"filter\";s:1:\"1\";s:8:\"zigclass\";s:11:\"Box-1-Redes\";}i:5;a:5:{s:5:\"title\";s:0:\"\";s:4:\"text\";s:426:\"<ul>\r\n 	<li><a href=\"#\">[icon name=\"phone\" class=\"\" unprefixed_class=\"\"] </a>+51 986 268 583</li>\r\n 	<li>[icon name=\"whatsapp\" class=\"\" unprefixed_class=\"\"] +51 914 248 899</li>\r\n 	<li>[icon name=\"envelope-open-o\" class=\"\" unprefixed_class=\"\"] <a href=\"mailto:reservas@peruconexiontravel.com\"> reservas@peruconexiontravel.com</a></li>\r\n 	<li><a href=\"https://peruconexiontravel.com/category/nuestro-blog\">Blog</a></li>\r\n</ul>\";s:4:\"type\";s:6:\"visual\";s:6:\"filter\";s:1:\"1\";s:8:\"zigclass\";s:11:\"Box-1-mails\";}i:6;a:5:{s:5:\"title\";s:0:\"\";s:4:\"text\";s:716:\"<h2>Viajeros que Confiaron en Nosotros</h2>\r\n<h3>Tour Machupicchu - Montaña 7 Colores</h3>\r\n<h4><strong>Viajero(a): Erick C - Viajo en Febrero aproximadamente</strong></h4>\r\nExcelente servicio; nos contactamos con ellos desde Guatemala, en dónde resolvieron nuestras dudas de manera rápida y amable. Al llegar a Cusco, nos recogieron en el aeropuerto y nos explicaron a detalle los recorridos y demás. Finalmente estuvieron muy al pendiente de nosotros durante todos los recorridos siempre preguntándonos si todo había estado bien y había sido lo esperado. Fue una excelente elección haber viajado con ellos. Completamente recomendable.\r\n\r\n<a href=\"#\">Revisa Nuestro Trip Advisor para mas Comentarios</a>\";s:4:\"type\";s:6:\"visual\";s:6:\"filter\";s:1:\"1\";s:8:\"zigclass\";s:19:\"boxTestimonioSingle\";}s:12:\"_multiwidget\";i:1;}','yes');
