INSERT INTO `pcta_postmeta` VALUES (380,66,'descripcion','Arequipa, también conocido como: ciudad blanca, heroica ciudad de los libres de Arequipa, ciudad caudillo, etc. es la segunda ciudad más grande del Perú, ubicada en la provincia y departamento homónimos.\r\nVisitaremos la plaza de armas, una de las más bellas del Perú, la Iglesia jesuita de la Compañía de Jesús, que en su bella fachada anuncia la denominada arquitectura mestiza, sus claustros y cúpula, la casona Tristán del Pozo; al final, para una magnífica vista de la ciudad, visitaremos los típicos distritos de Carmen alto y Yanahuara. (Mirador e Iglesia).\r\n');
