INSERT INTO `pcta_postmeta` VALUES (495,76,'descripcion','Visitar Cusco es siempre una gran aventura. Imagínense recorrer sus hermosos paisajes alto andinos y las zonas más icónicas que ofrece la capital del Imperio de los Incas. Con este tour podrán hacerlo y aún más emocionante, subidos a una bestia de metal con cuatro ruedas: un cuatrimoto. Admirar las grandes praderas rurales que el gran Valle del Sagrado ofrece y las que alguna vez el Inca contempló, pero con la dosis de adrenalina que sus cuerpos necesitan. visitarán el sitio arqueológico de Moray, denominado como un posible laboratorio de investigación agrícola incaico, donde observarán la particular distribución de sus andenes y los microclimas que se han replicado en ellos. Luego conocerán las salineras de Maras, una mina de sal explotada desde la época incaica y cuyo origen sigue siendo un misterio. ¡Atrévete a recorrer el camino inca como un explorador aguerrido y deja que el místico Cusco te deslumbre!');
