INSERT INTO `pcta_postmeta` VALUES (571,82,'descripcion','¡Sentirá como si estaría volando! A través del vuelo en la tirolesa, el participante tendrá la oportunidad de apreciar las diversas montañas y paraísos andinos, el Valle Sagrado de los Incas y la animada cultura de la comunidad Racchi. Después de la tirolesa, manejaremos durante 20 minutos para llegar a Chinchero. Aquí podremos admirar las paredes incaicas bien conservadas de la plaza principal, así como los muchos altares. También visitaremos la hermosa iglesia colonial, única por sus ilustraciones e imágenes interiores.');
