INSERT INTO `pcta_postmeta` VALUES (695,92,'descripcion','Cusco es la ciudad continuamente habitada más antigua en Sudamérica, la capital arqueológica de América y la ciudad más cosmopolita en Perú. Está plagada de contrastes, no solo en sus estructuras sino en todo respecto a ella; su cultura, sus celebraciones, su comida, las personas que viven en ella, etc.; acá podrá encontrar personas de todo el mundo.');
