INSERT INTO `pcta_postmeta` VALUES (720,94,'descripcion','Visitar Machupicchu constituye una experiencia inolvidable, lo místico que desprenden sus imponentes muros pétreos, inspiran un profundo respeto por los constructores de esta monumental obra, quienes supieron conjugar, como nadie en el mundo. La ciudad Inka de Machupicchu, está ubicado en medio de majestuosas montañas de ceja de selva su incomparable belleza y fuerza espiritual es privilegiada, la ciudad escondida dentro del trópico y construida con una localización geográfica privilegiada que combina con las montañas sagradas, agua corriente y un alineamiento celestial casi perfecto, un excelente trabajo en piedra y un gran número de terrazas para la agricultura, es impresionante.');
