INSERT INTO `pcta_postmeta` VALUES (1071,122,'descripcion','Llamada también Montaña de Siete Colores, Montaña Arcoíris o Montaña de Colores (los pobladores le llaman Cerro Colorado), es una montaña del Perú con una altitud de 5.200 msnm.\r\nEstá situada en el camino al nevado Ausangate, en los Andes del Perú, Región Cusco, entre los distritos de Cusipata, provincia de Quispicanchi, y Pitumarca, provincia de Canchis.');
