INSERT INTO `pcta_postmeta` VALUES (1121,126,'descripcion','Realice una excursión de medio día por la conocida Ciudad de los Reyes del Perú, Lima. En este tour podrá conocer los sitios más históricos, aquellos que poseen una bella arquitectura colonial, hermosos templos e iglesias, barrios residenciales, admirables paisajes alrededor del mar y demás atractivos turísticos de la capital peruana. Disfrute de este atractivo tanto en la mañana como en la tarde.');
