INSERT INTO `pcta_postmeta` VALUES (1170,130,'descripcion','Para conocer las maravillosas Islas de Uros y la isla natural de Taquile ubicadas a la altitud de 3812 msnm. ¡Es en esta última donde conocerás su magnífica playa (lugar único de la isla de Taquile) con arena blanca y con vistas espléndidas hacia los nevados de la Cordillera de los Andes!\r\nAdemás de estos bellos paisajes, gozarás de la maravillosa experiencia de compartir la esencia del hombre andino junto con las familias locales.\r\nUna placentera experiencia que te dejará hermosos recuerdos de las islas que te harán desear volver.\r\n');
