INSERT INTO `pcta_postmeta` VALUES (1296,140,'descripcion','Es el corazón de la Reserva de biosfera, es una de las áreas protegidas más importantes en el trópico sudamericano localizado en el franco oriental de las montañas andinas. El Parque Nacional del Manu protege una secuencia de paisaje natural intacta que desciende de los 4.200 mt. Hacia la extensa selva lluviosa en la zona amazónica.\r\nEl Manu es el refugio de muchas especies de animales en peligro de extinción, que incluye al jaguar, caimán negro, nutria giganta, águila arpía, etc. La Reserva del Manu hoy considerado el único hogar en la tierra con una gran biodiversidad de flora y fauna silvestre. El Manu alberga un promedio de 860 especies de aves que incluye 7 especies de coloridos papagayos, 84 especies de mamíferos que incluyen 13 especies de monos y miles de especies de insectos y plantas.\r\n');
