INSERT INTO `pcta_postmeta` VALUES (1471,154,'descripcion','Los mejores vinos y piscos, el misterio de un pueblo y los encantos de un oasis en el desierto te esperan, inicia el día degustando los mejores vinos y piscos de Ica ¡Siéntete un experto catador!\r\nAnímate a conocer los secretos de la ciudad, ¡Aprovecha la oportunidad para comprar los mejores recuerdos para los tuyos!, el Oasis de la Huacachina te espera, recorre el centro artesanal y llega hasta la Laguna, pasea, compra artesanía o anímate a practicar alguna actividad extrema, termina el día dejándote envolver por las historias de brujas y maldiciones en el Pueblo de Cachiche.\r\n');
