INSERT INTO `pcta_postmeta` VALUES (1596,164,'descripcion','Nuestro programa lo invita a visitar y disfrutar lo mejor de la costa sur de Perú, explorando el desierto con sus enigmáticas líneas de Nazca, disfrutando de sus dunas y Oasis donde tendrá la experiencia de practicar deportes de aventura como sandboarding o paseos en dunas. Además de visitar hermosos paisajes naturales de la Reserva Natural de Paracas privilegiada con una riqueza única de vida marina.');
