INSERT INTO `pcta_postmeta` VALUES (1621,166,'descripcion','Tour Reserva Nacional de Paracas nos hará disfrutar no solo de fabulosos paisajes marítimos y desérticos, sino también podremos aprender sobre el antiguo hombre Paracas, quien habito estas zona hace más de 2000 años, dejando como evidencia en sus necrópolis una gran diversidad de bellos tejidos, los cuales asombran al mundo moderno.\r\nEn la Península de Paracas también es posible disfrutar de un baño relajante en una de sus bellas playas o simplemente hacer caminatas alrededor de ellas en busca de fotografías.\r\n');
