INSERT INTO `pcta_postmeta` VALUES (1774,196,'descripcion','Este tour de aventura te ofrece la oportunidad de subir y disfrutar en la famosa duna más alta del mundo. Cerro blanco con más de 2090 msnm. que forma parte de las montañas andinas. \r\nRealizaremos una caminata por un agradable sendero y travesando hermosos paisajes. Una vez en la cima. podrás disfrutar de una vista paisajista en todo su esplendor de los valles de Nazca e impresionantes dunas formados por el capricho de la naturaleza. \r\nDonde podrás practicar el deporte de sandboard sobre inmensas dunas de arena que le harán disfrutar y experimentar una extrema adrenalina acompañado por nuestros experimentados guías.\r\n');
INSERT INTO `pcta_postmeta` VALUES (1775,196,'_descripcion','field_5e629af417021');
