INSERT INTO `pcta_postmeta` VALUES (1789,198,'descripcion','La cultura Nazca fue una civilización que pudo dominar este desierto tan árido gracias al desarrollo de una obra de ingeniería hidráulica, construidas en diferentes partes de valle fueron hechos con piedras lajas, canto rodado y troncos de Huarango para poder captar las aguas subterráneas. Uno de los que mejores se conservan son lo Acueductos de Cantalloc.');
