INSERT INTO `pcta_postmeta` VALUES (1838,206,'descripcion','Dos deportes de aventura uno consiste en abordar potentes y veloces carros tubulares o areneros, que trepan las dunas del desierto, elevando la adrenalina al máximo, paseos fantásticos que te llevaran por lugares espectaculares hasta las partes altas de las dunas.\r\nDesde ahí comienza la otra emoción, el sandbording, que te permite deslizarte sobre una tabla, sobre pendientes de dunas apropiadas. Dependiendo de tu habitad y del encerado de la base de la tabla, podrás alcanzar velocidades extremas en el descenso, sin riesgo de daños físico, excepto probable revolcada en la arena, es muy divertido.\r\n');
INSERT INTO `pcta_postmeta` VALUES (1839,206,'_descripcion','field_5e629af417021');
