INSERT INTO `pcta_postmeta` VALUES (1857,210,'descripcion','Las collpas de guacamayos es la formación arcillosa del por acción del rio y está ubicado en el barranco de los ríos. Todas las mañanas al amanecer los guacamayos, entre otras aves se dirigen a este lugar para ingerir por 30 minutos aprox. La razón por el cual estas aves consumen arcilla es por según los investigadores dicen que contiene sales vitales y minerales utilizadas en la dieta de los animales quienes consumen. Esta excursión es para todos sin excepción alguna, donde podrá vivir la emoción de sentir y escuchar la belleza del encanto de la naturaleza, en el transcurso de su estadía apreciará la fauna y bastante vegetación.');
