INSERT INTO `pcta_postmeta` VALUES (1878,215,'descripcion','La reserva de la selva de Tambopata se encuentra al sureste del Perú, a unas 14 horas en auto o 1 hora de vuelo desde Cusco. La Reserva es la segunda más grande del Perú (después del Parque Nacional Manú) con casi 275 hectáreas (680 acres) y con una desbordante vida silvestre.');
