INSERT INTO `pcta_postmeta` VALUES (1897,219,'descripcion','Experimenta Puerto Maldonado como todo un aventurero, anímate a explorar su hermosa selva y conocer su exquisita biodiversidad. Tendrá la oportunidad de vivir la magia de nuestra selva amazónica que está dentro de la Reserva Nacional Tambopata, (278,000 mil hectáreas protegidas), aprecia la belleza del lago Sandoval y navega sus aguas en un bote a remos y descubre tu lado extremo haciendo Canopy a una altura de 30 metros, desde donde podrás disfrutar de la hermosa vista panorámica de la densa selva tropical.');
INSERT INTO `pcta_postmeta` VALUES (1898,219,'_descripcion','field_5e629af417021');
