INSERT INTO `pcta_postmeta` VALUES (1912,221,'descripcion','El tour comprende una visita plena de experiencias a los dos más importantes atractivos de la región: la impresionante Colpa de Guacamayos en el Parque Nacional Bahuaja-Sonene y el paradisíaco Lago Sandoval en la Zona Reservada Tambopata-Candamo, además de posibles encuentros con animales silvestres. Un tour reservado para los amantes de la naturaleza, especial para los aficionados a la observación de aves y vida silvestre.');
