INSERT INTO `pcta_postmeta` VALUES (1969,233,'descripcion','El lago Sandoval es uno de los lagos más bellos del Perú; un gran cuerpo de agua protegido en la Reserva Nacional Tambopata. Es el hogar de una familia de nutrias gigantes en peligro de extinción, pero tenemos una excelente oportunidad de verlos durante nuestra estancia. Las orillas del lago están pobladas por selvas inundadas de Mauritia, que son el hogar de monos de seis especies diferentes, así como con una gran variedad de pájaros coloridos. Esta visita a la Reserva Nacional Tambopata nos permite observar el Lago Sandoval y el área circundante donde veremos una gran cantidad de vida silvestre en la reserva y aprender sobre la selva amazónica.');
