INSERT INTO `pcta_postmeta` VALUES (1984,235,'descripcion','La Reserva Nacional de Tambopata se encuentra en la cuenca del río Tambopata que cubre el sur del río Madre de Dios Región (40% de la reserva), así como Puno Región (60% de la reserva)! \r\nSu rica biodiversidad incluye 103 especies de mamíferos, 1.300 especies de mariposas, ¡90 especies de anfibios y 41 familias de árboles que contienen 165 especies de árboles! La reserva tiene una superficie de 274.690 hectáreas. El clima es cálido y húmedo con alta precipitación anual.\r\nDurante este recorrido, visitamos los dos más grandes de arcilla-licks de la Amazonía peruana: ¡¡Chuncho y Colorado!! Ambos están situados en la Zona Reservada de la Reserva Nacional Tambopata. El Colorado collpa se coloca en el banco del lado derecho del río Tambopata, mientras que el Chuncho es en el banco del lado izquierdo. Los arcilla-lame Chuncho y Colorado atraen un gran número de guacamayos, loros, pericos, ¡¡así como otros tipos de animales cada día!\r\n');
