INSERT INTO `pcta_postmeta` VALUES (2003,239,'descripcion','Dentro del lago mayor del Titicaca, habitan pueblos de hombres y mujeres solidarios que comparten su cultura, y sus tradiciones ancestrales. El viajero tiene la sensación de haber dado un salto en el tiempo, para revivir un pedazo de la grandiosa historia de los hijos del Sol. Estos nativos son grandes navegantes y maestros del tejido que preservan su sabiduría en los diseños y decoración de su vestimenta y en sus tradiciones. La isla es también de gran valor paisajístico por su ubicación en la inmensidad del lago.\r\nEste viaje es muy popular por la oportunidad de interactuar con los nativos que aún mantienen su inocencia de mente y corazón, debido al estilo de vida muy simple y tranquila que llevan. Las viviendas son muy sencillas y acogedoras, todas con vista al Lago, esta combinación de cultura y naturaleza hace de este lugar un encanto.');
