INSERT INTO `pcta_postmeta` VALUES (2035,244,'descripcion','La comunidad de los Uros habita pequeñas islas sobre el Lago Titicaca y lo han hecho durante cientos de años por el habitante tuvo que aprender a cosechar la totora, para luego juntarlas en grandes cantidades, unirlas por la raíz y así dar forma a sus pequeñas islas como si fueran plataformas. Estos pobladores también son conocidos como los hijos de la mama cocha que significa madre lago, pues tienen que mantener sus islas diariamente, agregando nuevas capas de “Totora” (planta del lago), asimismo sus hogares y sus botes están hechos de esa misma planta.');
INSERT INTO `pcta_postmeta` VALUES (2036,244,'_descripcion','field_5e629af417021');
