INSERT INTO `pcta_postmeta` VALUES (2141,264,'descripcion','Este tour es una nueva opción si lo que busca es una experiencia que sale más allá de lo tradicional en el cusco, en esta excursión de 3 días usted tendrá la oportunidad de ingresar de un clima frio a un clima caliente de la selva, y finalmente llegar a Machupicchu.');
