INSERT INTO `pcta_postmeta` VALUES (2253,288,'descripcion','Es un puente colgante construido a base de fibra vegetal (ichu) que se encuentra en el distrito de Quehue, provincia de Canas en el departamento del Cuzco a 3700 msnm cruzando el río Apurímac. La existencia de este puente data desde la época inca y su mantenimiento y renovación se realiza mediante un rito ejecutado por las comunidades de Huinchiri, Chaupibanda, Ccollana Quehue y Choccayhua.\r\nEl puente mide 28 metros de largo y 1.20 metros de ancho, su estructura está básicamente de tiras largas de ichu trenzado.\r\n');
