INSERT INTO `pcta_postmeta` VALUES (2295,298,'descripcion','Un paseo en bus por Cusco es la mejor opción para todos aquellos viajeros que deseen un viaje corto por la ciudad del Cusco, el bus panorámico en Cusco lo llevara por los lugares más representativos de la ciudad del Cusco y en solo unas cuantas horas podrás conocer la belleza de esta hermosa ciudad.');
