INSERT INTO `pcta_postmeta` VALUES (2310,300,'descripcion','Machu Picchu Full Day, viaje de un día hacia una de las obras maestras de la Ingeniería Civil y Arquitectura del Imperio Inca, construido en el corazón de la ceja selva bajo la protección de las montañas sagradas Huayna Picchu y Machu Picchu.\r\nLa ciudad Inca de Machu Picchu te está esperando, ten la experiencia única y mágica visitando a esta Maravilla del Mundo y Patrimonio Mixta Cultural y Natural de la Humanidad.');
