INSERT INTO `pcta_postmeta` VALUES (2325,302,'descripcion','Al tomar esta excursión de Machu Picchu By Car tendrá un hermoso panorama lleno de paisajes y nevados como Chicon, Salkantay y Verónica que muestra nuestra sierra andina.');
