INSERT INTO `pcta_postmeta` VALUES (2359,307,'descripcion','Ofrenda a la pachamama es una ceremonia o también conocida como “Pago a la Tierra” son rituales de origen ancestral, cuya finalidad es devolver a la tierra todo lo que nos ha dado. Estas ceremonias de ofrenda a la pachamama se realizan comúnmente el primer día de agosto, pero se pueden realizar cualquier día del Año.\r\nDentro de esta Ceremonia de ofrenda a la pachamama, para pedir nuestros más anhelados deseos para nuestra vida, lo que soñamos para nuestro futuro y lo que queremos para nuestros seres queridos. Todo esto basado en una conexión entre el mundo material y el espiritual.\r\n');
INSERT INTO `pcta_postmeta` VALUES (2360,307,'_descripcion','field_5e629af417021');
