INSERT INTO `pcta_postmeta` VALUES (2402,313,'descripcion','La Planta Maestra San Pedro o Wachuma es la conexión del hombre con la madre tierra (Pachamama) y el universo, con esta ceremonia nosotros nos reconectamos con algo con lo que nacimos, con nuestra esencia divina perteneciente a la madre tierra que muchas veces permanece dormida en nuestro interior y que con solo una intención la podemos volver a despertar.  Las ceremonias se realizan en lugares sagrados de los incas. Es considerada por los descendientes de los antiguos pueblos originarios de América la Planta Maestra, que era utilizada en la antigüedad para la limpieza y purificación del cuerpo, la mente y el espíritu');
INSERT INTO `pcta_postmeta` VALUES (2403,313,'_descripcion','field_5e629af417021');
