INSERT INTO `pcta_postmeta` VALUES (2417,315,'descripcion','“Retiros Espirituales con Ayahuasca en Cusco, Perú”, durante cuatro días. Los Retiros Espirituales se basan en una serie de conocimientos y técnicas chamánicas ancestrales que tienen la finalidad de despertar el poder de la curación interior. Los participantes tendrán la oportunidad de conocer y experimentar las bondades de la medicina tradicional andina y amazónica, especialmente de la planta madre Ayahuasca; de esta manera, iniciarán su camino personal hacia la armonía, la curación física, espiritual, mental y emocional.');
INSERT INTO `pcta_postmeta` VALUES (2418,315,'_descripcion','field_5e629af417021');
