INSERT INTO `pcta_postmeta` VALUES (3040,417,'descripcion','El camino Inca corto combina hermosos paisajes de montaña y vistas panorámicas increíbles, exuberante bosque nublado, una selva subtropical del espléndido entorno natural, con el magnífico trabajo de los Incas como una mezcla excepcional de pavimento de piedras colocados sobre el camino, la agricultura, terrazas, fuentes de agua, túneles y sitios arqueológicos sorprendentes como la famosa Puerta del Sol y de la puesta de sol sobre Machu Picchu. Esta caminata es ideal para aquellos que tienen tiempo limitado y aquellos que quieran tener una caminata fácil de lograr.');
