INSERT INTO `pcta_postmeta` VALUES (3883,527,'descripcion','Esta es una ruta alternativa al clásico Camino Inca a Machu Picchu, que lo llevará a través de paisajes increíbles y belleza natural con flora y fauna de la región. La caminata incluirá cruzar valles y montañas antes de llegar a la \"Ciudad Perdida de los Incas\", Machu Picchu.\r\nConectando la ciudad de Mollepata, Cusco con Machu Picchu, el Salkantay Trek es un antiguo y remoto sendero ubicado en la misma región que el Camino Inca donde enormes montañas nevadas chocan con exuberantes selvas tropicales.');
INSERT INTO `pcta_postmeta` VALUES (3884,527,'_descripcion','field_5e629af417021');
