INSERT INTO `pcta_postmeta` VALUES (4820,615,'descripcion','Linda Laguna de Humantay donde podremos apreciar los bellos escenarios de la cordillera de los andes peruanos, así como sus imponentes nevados Humantay y Salkantay.');
