INSERT INTO `pcta_postmeta` VALUES (4832,617,'descripcion','El Inka Jungle Trail 4D/3N combina diferentes actividades al aire libre, como biking, rafting, zip line y trekking, culminando en Machu Picchu y Huayna Picchu. Esta fabulosa experiencia la vivirás con sus guías especializados en este rubro, conocedores de la ruta durante años de recorrido y con vasta experiencia.');
