INSERT INTO `pcta_postmeta` VALUES (4843,619,'_duracion','field_5e629a9f17020');
INSERT INTO `pcta_postmeta` VALUES (4844,619,'descripcion','El Camino Inca a Machupicchu está catalogado como una de las mejores caminatas en todo el mundo por lo exquisito de su belleza y maravillosos alrededores naturales, es una experiencia espectacular que hay que realizar a menos una vez en la vida. Tiene un recorrido de 42 km desde el km 82 hasta la Ciudadela de Machu Picchu. Personas de todo el mundo vienen a Perú para realizarlo.');
INSERT INTO `pcta_postmeta` VALUES (4845,619,'_descripcion','field_5e629af417021');
