INSERT INTO `pcta_postmeta` VALUES (4856,620,'descripcion','En la visita a este importante atractivo turístico podremos apreciar muchos monumentos arqueológicos de la época Inca, ríos importantes del Cusco y pueblos andinos. El valle ha sido apreciado desde la antigüedad por los incas gracias a la geografía y el clima de la zona. Fue considerado como uno de los principales lugares de producción por sus fértiles tierras donde se realiza la producción del mejor maíz en el Perú.');
INSERT INTO `pcta_postmeta` VALUES (4857,620,'_descripcion','field_5e629af417021');
