INSERT INTO `pcta_postmeta` VALUES (4868,621,'descripcion','El Valle Sagrado de los Incas, en los Andes peruanos, está compuesto por numerosos ríos que descienden por quebradas y pequeños valles; posee numerosos monumentos arqueológicos y pueblos indígenas.\r\nEste valle fue muy apreciado por los incas debido a sus especiales cualidades geográficas y climáticas. Fue uno de los principales puntos de producción por la riqueza de sus tierras y lugar en donde se produce el mejor grano de maíz en el Perú.');
INSERT INTO `pcta_postmeta` VALUES (4869,621,'_descripcion','field_5e629af417021');
