INSERT INTO `pcta_postmeta` VALUES (4904,624,'descripcion','En la visita a este importante atractivo turístico podremos apreciar muchos monumentos arqueológicos de la época Inca, ríos importantes del Cusco y pueblos andinos. El valle ha sido apreciado desde la antigüedad por los incas gracias a la geografía y el clima de la zona. Fue considerado como uno de los principales lugares de producción por sus fértiles tierras donde se realiza la producción del mejor maíz en el Perú.');
