INSERT INTO `pcta_posts` VALUES (34,1,'2020-03-06 19:12:22','2020-03-06 19:12:22','a:10:{s:4:\"type\";s:4:\"text\";s:12:\"instructions\";s:0:\"\";s:8:\"required\";i:0;s:17:\"conditional_logic\";i:0;s:7:\"wrapper\";a:3:{s:5:\"width\";s:2:\"20\";s:5:\"class\";s:0:\"\";s:2:\"id\";s:0:\"\";}s:13:\"default_value\";i:20;s:11:\"placeholder\";s:0:\"\";s:7:\"prepend\";s:0:\"\";s:6:\"append\";s:0:\"\";s:9:\"maxlength\";s:0:\"\";}','Precio del Tour','precio','publish','closed','closed','','field_5e62a061a38d2','','','2023-04-15 22:17:41','2023-04-15 22:17:41','',25,'https://peruconexiontravel.com/?post_type=acf-field&#038;p=34',2,'acf-field','',0);
INSERT INTO `pcta_posts` VALUES (591,1,'2020-11-04 15:38:26','2020-11-04 15:38:26','Cusco siempre será uno de los lugares más visitados por decenas o cientos de visitantes a diario, viajeros nacionales e internacionales recorren sus calles a y todos quedan totalmente impresionados de toda la magia que esta ciudad ofrece a sus visitantes.\r\n\r\nSi planeas viajar a Cusco o ya tienes organizado un viaje a Machupicchu Perú, hacer una escala en la ciudad del Cusco la antigua capital del imperio es algo infaltable en tu itinerario de viaje.\r\n\r\nEl mejor lugar para conocer dentro de la ciudad del Cusco es El Qoricancha o Templo del Sol, No te pierdas este lugar si están en Cusco. Es en donde se puede apreciar la arquitectura imperial en su máxima perfección.\r\n\r\nTours los tours por la ciudad del Cusco te llevan al Qoricancha que algunos consideran un museo – iglesia muy bonito (Lamentablemente NO puedes sacar fotos del interior, pero si de la fachada o desde las calles del Cusco aledañas.\r\n\r\nAlgunos viajeros toman la decisión de conocer el Qoricancha por su cuenta basándose inicialmente en la basta información que obtienen desde internet o las guías mundiales de viajeros y otros prefieren organizar sus viajes y visitas al Templo del Sol con una agencia de viajes de Cusco.\r\n\r\nEl templo del Sol o Qoricancha tienen muchos cuadros y piezas hermosas, pero solo tienes que sacarle una fotografía mental porque no puedes sacar fotografías.\r\n\r\nEl templo del Sol está en pleno casco histórico a solo unos metros de la Plaza de Armas de la ciudad del Cusco y forma parte del circuito turístico del CITY TOUR DE MEDIO DIA en Cusco, es un lugar que vale la pena conocer, está construida desde la época de la conquista y conserva asentamientos Incas por los cuales pueden pasar tocar o simplemente observar, puedes obtener fotos hermosas, en las salas igualmente puedes apreciar exposiciones del arte de la Escuela Cusqueña, que fue influenciada por maestros italianos traídos en el en el siglo XVI aproximadamente para enseñar a los aborígenes convertidos al cristianismo pintura religiosa, y maravilla ver que crearon un estilo único que releva su propia cultura, para los conocedores de arte, es una maravilla.\r\n\r\nConocer el Qorikancha o iglesia de Santo Domingo en una visita guida con profesionales en turismo que son excelentes permite conocer a los viajeros cada rincón de Qorikancha y saber cada misterio que sus paredes.\r\n\r\nRecomendación: Lo recomendable es conocer el Qoricancha con guías oficiales, no, los que se ofrecen en la puerta, sino los de las agencias de viajes oficiales en Cusco. Un lugar imperdible para visitar hasta dos veces.\r\n\r\nTodo viajero debe venir a este lugar, no solo es histórico, tiene un paisaje muy genial tanto de día con sus bellos jardines y muros de piedra originales Inka, sino también por su galería de arte interna, de noche tiene una espectacular vista como para fotografiarse.\r\n\r\nEl City tour en Cusco por lo general tiene una duración de Medio día (6 a 7 horas aproximadamente) cuando el tour termina por lo general las agencias de viajes dejan a los viajeros en el centro de la ciudad puedes aprovechar caminar un poco y volver a este increíble lugar y tomarte algunas fotos que serán espectaculares desde las afueras del Qoricancha\r\n\r\n<img class=\"aligncenter wp-image-593 size-full\" src=\"https://peruconexiontravel.com/wp-content/uploads/2020/11/templodelsol.png\" alt=\"\" width=\"865\" height=\"400\" />','No pierdas la oportunidad de viajar a Cusco Peru y conocer el Templo del Sol','','publish','open','open','','no-pierdas-la-oportunidad-de-viajar-a-cusco-peru-y-conocer-el-templo-del-sol','','','2023-04-15 21:24:05','2023-04-15 21:24:05','',0,'https://peruconexiontravel.com/?p=591',0,'post','',0);
