INSERT INTO `pcta_posts` VALUES (52,1,'2020-03-06 22:09:15','2020-03-06 22:09:15','[tabby title=\"Resúmen\"]\r\n<h2>Resumen de nuestro viaje para el Inti Raymi 2019</h2>\r\n<ul>\r\n 	<li><strong>DIA 1:</strong> Llegada a la ciudad del Cusco, tour por el Valle Sagrado de los Incas y viaje a Machu Picchu</li>\r\n 	<li><strong>DIA 2:</strong> Tour en Machupicchu y retorno a la ciudad del Cusco</li>\r\n 	<li><strong>DIA 3:</strong> Apreciaremos la <strong>festividad del Inti Raymi 2019</strong> desde la zona VIP o Tribuna Naranja</li>\r\n 	<li><strong>DIA 4:</strong> Tour a Vinincunca o Montaña de Colores</li>\r\n 	<li><strong>DIA 5:</strong> Final del viaje</li>\r\n</ul>\r\n<h3>DÍA 1:</h3>\r\n• 07:40 hrs. Recojo del hotel para comenzar el recorrido\r\n• 08:00 hrs. Comienza el Tour del Valle Sagrado\r\n• Recorre el Valle Sagrado de los Incas. Visitaremos Pisac, almorzaremos en Urubamba e iremos a Ollantaytambo.\r\n• 19:40 hrs. Salida del tren vía PeruRail desde Ollantaytambo a Aguas Calientes\r\n• 20:45 hrs. Llegada al pueblo de Aguas Calientes\r\n• Transporte al hotel\r\n<h3>DÍA 2:</h3>\r\n• 06:00 hrs. Aborda el bus a Machupicchu\r\n• 07:00 hrs. Visita guiada de 2 horas en Machupicchu\r\n• Abordar el autobús de regreso a Aguas Calientes\r\n• 16:22 hrs. Regreso en tren de Aguas Calientes a Ollantaytambo\r\n• 20:32 hrs. Llegada a la estación de Ollanta\r\n• 22:30 hrs. Aprox. llegada a la ciudad de Cusco\r\n\r\nPrecio: $ 325.00 USD Las\r\n\r\nreservas deben hacerse con un mes de anticipación.\r\nPor favor compre el boleto turístico.\r\nLas salidas se realizan a diario.\r\n<h2>Dia 1 - Recojo de hotel par partir:</h2>\r\nEste lugar es una maravilla del mundo, conoce cada rincón de su misterioso y acogedor espacio turístico, que marcara tu vida de inicio a fin hasta el retorno a tu planeta, acogedor espacio turístico, que marcara tu vida de inicio a fin hasta el retorno a tu planeta. Este lugar es una maravilla del mundo, conoce cada rincón de su misterioso y acogedor espacio turístico, que marcara tu vida de inicio a fin hasta el retorno a tu planeta, acogedor espacio turístico, que marcara tu vida de inicio a fin hasta el retorno a tu planeta. Este lugar es una maravilla del mundo, conoce cada rincón de su misterioso y acogedor espacio turístico, que marcara tu vida de inicio a fin hasta el retorno a tu planeta, acogedor espacio turístico, que marcara tu vida de inicio a fin hasta el retorno a tu planeta. Este lugar es una maravilla del mundo, conoce cada rincón de su misterioso y acogedor espacio turístico, que marcara tu vida de inicio a fin hasta el retorno a tu planeta, acogedor espacio turístico, que marcara tu vida de inicio a fin hasta el retorno a tu planeta\r\n\r\n[tabby title=\"Itinerario\"]\r\n<h3>DÍA 1:</h3>\r\n• 07:40 hrs. Recojo del hotel para comenzar el recorrido\r\n• 08:00 hrs. Comienza el Tour del Valle Sagrado\r\n• Recorre el Valle Sagrado de los Incas. Visitaremos Pisac, almorzaremos en Urubamba e iremos a Ollantaytambo.\r\n• 19:40 hrs. Salida del tren vía PeruRail desde Ollantaytambo a Aguas Calientes\r\n• 20:45 hrs. Llegada al pueblo de Aguas Calientes\r\n• Transporte al hotel\r\n<h3>DÍA 2:</h3>\r\n• 06:00 hrs. Aborda el bus a Machupicchu\r\n• 07:00 hrs. Visita guiada de 2 horas en Machupicchu\r\n• Abordar el autobús de regreso a Aguas Calientes\r\n• 16:22 hrs. Regreso en tren de Aguas Calientes a Ollantaytambo\r\n• 20:32 hrs. Llegada a la estación de Ollanta\r\n• 22:30 hrs. Aprox. llegada a la ciudad de Cusco\r\n\r\nPrecio: $ 325.00 USD Las\r\n\r\nreservas deben hacerse con un mes de anticipación.\r\nPor favor compre el boleto turístico.\r\nLas salidas se realizan a diario.\r\n<h2>Dia 1 - Recojo de hotel par partir:</h2>\r\nEste lugar es una maravilla del mundo, conoce cada rincón de su misterioso y acogedor espacio turístico, que marcara tu vida de inicio a fin hasta el retorno a tu planeta, acogedor espacio turístico, que marcara tu vida de inicio a fin hasta el retorno a tu planeta. Este lugar es una maravil