INSERT INTO `pcta_posts` VALUES (100,1,'2020-03-12 23:13:02','2020-03-12 23:13:02','[tabby title=\"Itinerario\"]\r\n<h2>Día 1: Paseo en Bus Panorámico Cusco</h2>\r\nEl paseo en bus panorámico se inicia reuniéndonos en la Plaza de Armas al costado de la compañía de Jesús, donde se iniciará una caminata de 15min por la calle Loreto en donde apreciaremos muros incas y luego apreciaremos el Koricancha para después dirigirnos a la Avenida Paseo de los Héroes donde abordaremos el bus.\r\n\r\nLuego de abordar el bus nos dirigimos hacia la avenida el sol donde apreciaremos la Paqcha Pumacchupan, el mural histórico de Cusco y el Palacio de Justicia.\r\n\r\nSiguiendo la ruta hacia Sacsayhuamán tendremos una pequeña parada en el mirador de san Cristóbal donde se encuentra la iglesia del mismo nombre lugar ideal para realizar algunas fotos.\r\n\r\nRealizaremos una parada en un mirador de Sacsayhuamán para tomar fotos panorámicas.\r\n\r\nLuego nos dirigiremos a la laguna de Huayllarcocha donde serán participes del ritual a la hoja de coca después siguiendo la ruta haremos una pequeña parada en Pucapucara para tomar fotos y regresar a la ciudad.\r\n\r\nEn la ruta del regreso al Cusco visitaremos el mirador de Cristo Blanco de donde podrá apreciar en todo su esplendor la Ciudad del Cusco.\r\n\r\nPara finalizar el tour visitaremos las catacumbas del Convento de San Francisco donde podrá apreciar también grandes lienzos y pinturas\r\n\r\n[tabby title=\"Incluyen\"]\r\n<h2>Incluye</h2>\r\n<ul>\r\n 	<li>Bus panorámico</li>\r\n 	<li>Guía profesional bilingüe</li>\r\n 	<li>Ingreso a las catacumbas</li>\r\n</ul>\r\n<h2>No incluye</h2>\r\n<ul>\r\n 	<li>Alimentación no mencionada en el programa</li>\r\n 	<li>Gatos personales</li>\r\n 	<li>propinas</li>\r\n</ul>\r\n[tabbyending]','Paseo Bus Panorámico','','publish','open','open','','paseo-bus-panoramico','','','2023-04-15 22:21:06','2023-04-15 22:21:06','',0,'https://peruconexiontravel.com/?p=100',0,'post','',0);
