INSERT INTO `pcta_posts` VALUES (102,1,'2020-03-12 23:14:26','2020-03-12 23:14:26','[tabby title=\"Itinerario\"]\r\n<h2>Día 1: Cusco - Maras</h2>\r\n<ol>\r\n 	<li><strong> . Moray:</strong> Nuestra visita termina visitando las terrazas circulares de Moray, las cuales son una muestra de cómo el hombre andino desafío a la naturaleza y aprovecharon su medio geográfico para utilizarlo en su beneficio, estos andenes circulares sirvieron de laboratorio agrícola que permitió obtener una gran variedad de especies de papa, maíz, entre otros productos.</li>\r\n 	<li><strong> Maras:</strong> El poblado de Maras será nuestro primer punto de visita; el cual fue de gran importancia durante el Virreinato, declarado Villa de San Francisco de Asís (fue el principal abastecedor de sal de la sierra meridional), así lo demuestran la iglesia y las casonas que aún conservan los escudos de nobleza indígena en sus fachadas.</li>\r\n 	<li><strong> Salineras de Maras:</strong> Las Salineras de Maras nuestro segundo punto de visita pertenece al poblado Maras, el cual fue de gran importancia durante el Virreinato, fue el principal abastecedor de sal de la sierra meridional, así lo demuestran la iglesia y las casonas que aún conservan los escudos de nobleza indígena en sus fachadas. Las Minas de sal de Maras sorprenden al visitante por los más de tres mil pozos que presenta y que en la actualidad siguen siendo trabajados por más de 360 familias, quienes han heredado esta costumbre y labor extractiva artesanal; la comercialización de la sal se encuentra a cargo de la asociación Maras Sal, encargada de velar por intereses de la comunidad desde finales de los años 80.</li>\r\n</ol>\r\n[tabby title=\"Incluyen\"]\r\n<h2>Incluye</h2>\r\n<ul>\r\n 	<li>Transporte</li>\r\n 	<li>Guía profesional bilingüe</li>\r\n</ul>\r\n<h2>No incluye</h2>\r\n<ul>\r\n 	<li>Alimentación</li>\r\n 	<li>BTP (boleto turístico parcial)</li>\r\n</ul>\r\n[tabbyending]','Tour Maras Moray y Salineras','','publish','open','open','','tour-maras-moray-y-salineras','','','2023-04-15 22:21:06','2023-04-15 22:21:06','',0,'https://peruconexiontravel.com/?p=102',0,'post','',0);
INSERT INTO `pcta_posts` VALUES (103,1,'2020-03-12 23:14:26','2020-03-12 23:14:26','[tabby title=\"Itinerario\"]\r\n<h2>Día 1: Cusco - Maras</h2>\r\n<ol>\r\n 	<li><strong> . Moray:</strong> Nuestra visita termina visitando las terrazas circulares de Moray, las cuales son una muestra de cómo el hombre andino desafío a la naturaleza y aprovecharon su medio geográfico para utilizarlo en su beneficio, estos andenes circulares sirvieron de laboratorio agrícola que permitió obtener una gran variedad de especies de papa, maíz, entre otros productos.</li>\r\n 	<li><strong> Maras:</strong> El poblado de Maras será nuestro primer punto de visita; el cual fue de gran importancia durante el Virreinato, declarado Villa de San Francisco de Asís (fue el principal abastecedor de sal de la sierra meridional), así lo demuestran la iglesia y las casonas que aún conservan los escudos de nobleza indígena en sus fachadas.</li>\r\n 	<li><strong> Salineras de Maras:</strong> Las Salineras de Maras nuestro segundo punto de visita pertenece al poblado Maras, el cual fue de gran importancia durante el Virreinato, fue el principal abastecedor de sal de la sierra meridional, así lo demuestran la iglesia y las casonas que aún conservan los escudos de nobleza indígena en sus fachadas. Las Minas de sal de Maras sorprenden al visitante por los más de tres mil pozos que presenta y que en la actualidad siguen siendo trabajados por más de 360 familias, quienes han heredado esta costumbre y labor extractiva artesanal; la comercialización de la sal se encuentra a cargo de la asociación Maras Sal, encargada de velar por intereses de la comunidad desde finales de los años 80.</li>\r\n</ol>\r\n[tabby title=\"Incluyen\"]\r\n<h2>Incluye</h2>\r\n<ul>\r\n 	<li>Transporte</li>\r\n 	<li>Guía profesional bilingüe</li>\r\n</ul>\r\n<h2>No incluye</h2>\r\n<ul>\r\n 	<li>Alimentación</li>\r\n 	<li>BTP (boleto turístico parcial)</li>\r\n</ul>\r\n[tabbyending]','Tour Maras Moray y Salineras','','inherit','closed','closed','','102-revision-v1','','','2020-03-12 23:14:26','2020-03-12 23:14:26','',102,'https://peruconexiontravel.com/2020/03/12/102-revision-v1/',0,'revision','',0);
INSERT INTO `pcta_posts` VALUES (104,1,'2020-03-12 23:15:11','2020-03-12 23:15:11','[tabby title=\"Itinerario\"]\r\n<h2>Día 1: Cusco - Cuatro lagunas - Queswachaca</h2>\r\nEl viaje inicia en la ciudad del Cusco con el recojo de su hotel a las 7 a.m. aproximadamente con dirección sur-oeste. Después de casi dos horas de viaje visitaremos las cuatro lagunas: Laguna de Pomacanchi, Laguna de Acopia, Laguna Asnaqocha y la laguna Pampamarca o Tungasuca. Después de disfrutar de un momento tranquilo cerca de las lagunas, el siguiente lugar que visitaremos será el pequeño volcán de pabellones que está ubicado cerca al pueblo de Yanaoca.\r\n\r\nFinalmente llegaremos al rio Apurímac y al impresionante puente Inca.\r\n\r\nTendremos la oportunidad de cruzar el puente Inca hasta en dos oportunidades claro si tiene el coraje de hacerlo, pues puede parecer fácil. Pero sin lugar a dudas usted sentirá una gran emoción al cruzar este puente tanto así que se sentirá como un Chaski (mensajero inca). Camino de regreso a Combapata nos espera nuestro delicioso almuerzo en este poblado donde posteriormente haremos una última visita, el puente inca colonial de Combapata donde usted podrá ver las diferencias entre ambos puentes. Este interesante viaje termina en la ciudad de Cusco a las 5.00 pm aproximadamente.\r\n\r\n[tabby title=\"Incluyen\"]\r\n<h2>Incluye</h2>\r\n<ul>\r\n 	<li>Transporte privado Cusco - Queswachaca - Cusco</li>\r\n 	<li>Guía profesional bilingüe</li>\r\n 	<li>Almuerzo</li>\r\n 	<li>Boleto de entrada</li>\r\n</ul>\r\n<h2>No incluye</h2>\r\n<ul>\r\n 	<li>Desayuno</li>\r\n</ul>\r\n[tabbyending]','Tour Puente Queswachaka','','publish','open','open','','tour-puente-queswachaka','','','2023-04-15 22:21:06','2023-04-15 22:21:06','',0,'https://peruconexiontravel.com/?p=104',0,'post','',0);
INSERT INTO `pcta_posts` VALUES (105,1,'2020-03-12 23:15:11','2020-03-12 23:15:11','[tabby title=\"Itinerario\"]\r\n<h2>Día 1: Cusco - Cuatro lagunas - Queswachaca</h2>\r\nEl viaje inicia en la ciudad del Cusco con el recojo de su hotel a las 7 a.m. aproximadamente con dirección sur-oeste. Después de casi dos horas de viaje visitaremos las cuatro lagunas: Laguna de Pomacanchi, Laguna de Acopia, Laguna Asnaqocha y la laguna Pampamarca o Tungasuca. Después de disfrutar de un momento tranquilo cerca de las lagunas, el siguiente lugar que visitaremos será el pequeño volcán de pabellones que está ubicado cerca al pueblo de Yanaoca.\r\n\r\nFinalmente llegaremos al rio Apurímac y al impresionante puente Inca.\r\n\r\nTendremos la oportunidad de cruzar el puente Inca hasta en dos oportunidades claro si tiene el coraje de hacerlo, pues puede parecer fácil. Pero sin lugar a dudas usted sentirá una gran emoción al cruzar este puente tanto así que se sentirá como un Chaski (mensajero inca). Camino de regreso a Combapata nos espera nuestro delicioso almuerzo en este poblado donde posteriormente haremos una última visita, el puente inca colonial de Combapata donde usted podrá ver las diferencias entre ambos puentes. Este interesante viaje termina en la ciudad de Cusco a las 5.00 pm aproximadamente.\r\n\r\n[tabby title=\"Incluyen\"]\r\n<h2>Incluye</h2>\r\n<ul>\r\n 	<li>Transporte privado Cusco - Queswachaca - Cusco</li>\r\n 	<li>Guía profesional bilingüe</li>\r\n 	<li>Almuerzo</li>\r\n 	<li>Boleto de entrada</li>\r\n</ul>\r\n<h2>No incluye</h2>\r\n<ul>\r\n 	<li>Desayuno</li>\r\n</ul>\r\n[tabbyending]','Tour Puente Queswachaka','','inherit','closed','closed','','104-revision-v1','','','2020-03-12 23:15:11','2020-03-12 23:15:11','',104,'https://peruconexiontravel.com/2020/03/12/104-revision-v1/',0,'revision','',0);
INSERT INTO `pcta_posts` VALUES (106,1,'2020-03-12 23:16:13','2020-03-12 23:16:13','[tabby title=\"Itinerario\"]\r\n<h2>Día 1: Cusco - valle sagrado - Aguas Calientes</h2>\r\nSe inicia el recorrido con el recojo en su hotel a las 8:00 hrs.  Luego iremos rumbo al original poblado de Pisac donde visitaremos su mercado artesanal y parte de su grupo arqueológico, en el recorrido pasaremos por Coya, Lamay, Calca y en Urubamba en donde tendremos un almuerzo buffet. Se continúa el viaje al parque arqueológico de Ollantaytambo, luego de esta visita en la tarde, finalmente a las 16:36 hrs. tendremos conexión con el tren hacia el pueblo de Aguas Calientes. Recepción y traslado al hotel.\r\n<h2>Día 2: Aguas Calientes - Machu Picchu – Cusco</h2>\r\nDespués del desayuno, abordaremos el bus que nos transportará a Machu Picchu para ver la salida del sol, tendremos la ansiada visita a Machu Picchu acompañados por nuestro guía, habrá tiempo para explorar y aprender más sobre esta maravillosa ciudad Inca. Por la tarde volveremos en bus a Aguas Calientes para tomar el tren de retorno a Cusco. Recepción y traslado al Hotel.\r\n\r\n[tabby title=\"Incluyen\"]\r\n<h2>Incluye</h2>\r\n<ul>\r\n 	<li>·         Transporte turístico durante la visita al Valle Sagrado.</li>\r\n 	<li>·         Ticket de tren Ollantaytambo - Aguas Calientes - Ollantaytambo.</li>\r\n 	<li>·         Guía profesional bilingüe.</li>\r\n 	<li>·         Ticket de ingreso a Machu Picchu</li>\r\n 	<li>·         Ticket de bus Aguas calientes - Machu Picchu - Aguas calientes.</li>\r\n 	<li>·         Transporte Turístico de retorno Ollantaytambo - Cusco.</li>\r\n 	<li>·         Hotel en Aguas Calientes con Desayuno.</li>\r\n</ul>\r\n<h2>No incluye</h2>\r\n<ul>\r\n 	<li>·         Boleto Turístico BTG.</li>\r\n 	<li>·         Alimentación el segundo día.</li>\r\n</ul>\r\n[tabbyending]','Tour Valle Sagrado Conexión Machu Picchu','','publish','open','open','','tour-valle-sagrado-conexion-machu-picchu','','','2023-04-15 22:51:34','2023-04-15 22:51:34','',0,'https://peruconexiontravel.com/?p=106',0,'post','',0);
