INSERT INTO `pcta_posts` VALUES (110,1,'2020-03-12 23:17:40','2020-03-12 23:17:40','[tabby title=\"Itinerario\"]\r\n<h2>Día 1: Cusco - Tipón</h2>\r\nhora de recojo en el hotel a las 08:00 hrs. Para luego desplazarnos hacia el centro arqueológico de Tipón, luego no dirigiremos a la ciudadela pre-inca de Pikillaqta y para luego finalizar el tour en la Iglesia de San Pedro conocida como “La capilla Sixtina de America” ubicado en el distrito de Andahuaylillas.\r\n\r\n[tabby title=\"Incluyen\"]\r\n<h2>Incluye</h2>\r\n<ul>\r\n 	<li>Guía profesional bilingüe</li>\r\n 	<li>Transporte</li>\r\n</ul>\r\n<h2>No incluye</h2>\r\n<ul>\r\n 	<li>Alimentación</li>\r\n 	<li>BTP (boleto turístico parcial)</li>\r\n 	<li>Boleto de ingreso a Andahuaylillas</li>\r\n</ul>\r\n[tabbyending]','Valle Sur Cusco','','publish','open','open','','valle-sur-cusco','','','2023-04-15 22:21:06','2023-04-15 22:21:06','',0,'https://peruconexiontravel.com/?p=110',0,'post','',0);
