INSERT INTO `pcta_posts` VALUES (154,1,'2020-03-13 15:02:45','2020-03-13 15:02:45','[tabby title=\"Itinerario\"]\r\n<h2>Día 1: Ica</h2>\r\nHora de inicio del tour: 1:00 p.m.\r\n\r\nPunto de Encuentro: Recojo en hotel o Estación de Buses\r\n\r\nEl tour te permitirá conocer bodegas vitivinícolas artesanales, en las cuales podrás degustar vinos y piscos de gran calidad.\r\n\r\nPartida con Destino a la Huacachina y el centro artesanal. Se darán 2 horas libres, oportunidad para comprar artesanías (libre), o practicar alguna actividad en el desierto como sandboard (no incluido) o paseos en tubulares (no incluido) o realizar paseos en bote por la laguna (no incluido)\r\n\r\nPartida con destino a Cachiche. Conoce la historia de sus brujas y sus antiguas leyendas.\r\n\r\n6:30 p.m. Fin del tour.\r\n\r\n[tabby title=\"Incluyen\"]\r\n<h2>Incluye</h2>\r\n<ul>\r\n 	<li>Recojo en hoteles ubicados en el centro de la ciudad y estación de buses.</li>\r\n 	<li>Degustación de Vinos y Piscos.</li>\r\n 	<li>Visita a Bodegas Vitivinícolas.</li>\r\n 	<li>Paseo por la Ciudad.</li>\r\n 	<li>Visita a la Huacachina.</li>\r\n 	<li>Transporte Turístico.</li>\r\n 	<li>Guía de Turismo.</li>\r\n</ul>\r\n<h2>No incluye</h2>\r\n<ul>\r\n 	<li></li>\r\n 	<li>Paseos en Tubulares.</li>\r\n 	<li>Comidas ni Bebidas.</li>\r\n 	<li>Ningún otro punto no establecido en el tour.</li>\r\n</ul>\r\n[tabbyending]','City Tour Ica','','publish','open','open','','city-tour-ica','','','2023-04-15 22:21:23','2023-04-15 22:21:23','',0,'https://peruconexiontravel.com/?p=154',0,'post','',0);
INSERT INTO `pcta_posts` VALUES (155,1,'2020-03-13 15:02:45','2020-03-13 15:02:45','[tabby title=\"Itinerario\"]\r\n<h2>Día 1: Ica</h2>\r\nHora de inicio del tour: 1:00 p.m.\r\n\r\nPunto de Encuentro: Recojo en hotel o Estación de Buses\r\n\r\nEl tour te permitirá conocer bodegas vitivinícolas artesanales, en las cuales podrás degustar vinos y piscos de gran calidad.\r\n\r\nPartida con Destino a la Huacachina y el centro artesanal. Se darán 2 horas libres, oportunidad para comprar artesanías (libre), o practicar alguna actividad en el desierto como sandboard (no incluido) o paseos en tubulares (no incluido) o realizar paseos en bote por la laguna (no incluido)\r\n\r\nPartida con destino a Cachiche. Conoce la historia de sus brujas y sus antiguas leyendas.\r\n\r\n6:30 p.m. Fin del tour.\r\n\r\n[tabby title=\"Incluyen\"]\r\n<h2>Incluye</h2>\r\n<ul>\r\n 	<li>Recojo en hoteles ubicados en el centro de la ciudad y estación de buses.</li>\r\n 	<li>Degustación de Vinos y Piscos.</li>\r\n 	<li>Visita a Bodegas Vitivinícolas.</li>\r\n 	<li>Paseo por la Ciudad.</li>\r\n 	<li>Visita a la Huacachina.</li>\r\n 	<li>Transporte Turístico.</li>\r\n 	<li>Guía de Turismo.</li>\r\n</ul>\r\n<h2>No incluye</h2>\r\n<ul>\r\n 	<li></li>\r\n 	<li>Paseos en Tubulares.</li>\r\n 	<li>Comidas ni Bebidas.</li>\r\n 	<li>Ningún otro punto no establecido en el tour.</li>\r\n</ul>\r\n[tabbyending]','City Tour Ica','','inherit','closed','closed','','154-revision-v1','','','2020-03-13 15:02:45','2020-03-13 15:02:45','',154,'https://peruconexiontravel.com/2020/03/13/154-revision-v1/',0,'revision','',0);
INSERT INTO `pcta_posts` VALUES (156,1,'2020-03-13 15:03:31','2020-03-13 15:03:31','[tabby title=\"Itinerario\"]\r\n<h2>Día 1: Nazca</h2>\r\nNuestro recorrido comprende desde el recojo del hotel seleccionado en Ica y salida con destino a la ciudad de Nasca. Visita La Casa Museo María Reiche, aquí se aprecian los ambientes donde vivió y los trabajos que realizaba durante su existencia, así como su Tumba. Después se visita un Mirador ubicado a orillas de la panamericana sur, donde se observarán dos importantes figuras de las líneas de Nasca como la figura de Manos y la figura del árbol, después de unos minutos continuamos hasta llegar al aeródromo principal para realizar el sobrevuelo local a las enigmáticas líneas de Nasca donde apreciaremos las principales figuras desde lo alto como la Araña, el Perro, el Colibrí, el Cóndor, la Garza, el Árbol, las Manos, entre otros. Por la tarde al finalizar retornamos a hotel elegido en Ica o Nazca.\r\n\r\n[tabby title=\"Incluyen\"]\r\n<h2>Incluye</h2>\r\n<ul>\r\n 	<li>Traslado desde su hotel</li>\r\n 	<li>Servicios en transporte de turismo privado</li>\r\n 	<li>Guía de turismo Bilingüe Español – inglés.</li>\r\n</ul>\r\n<h2>No incluye</h2>\r\n<ul>\r\n 	<li>Almuerzo</li>\r\n 	<li>propinas</li>\r\n</ul>\r\n[tabbyending]','City Tour Nazca','','publish','open','open','','city-tour-nazca','','','2023-04-15 22:21:23','2023-04-15 22:21:23','',0,'https://peruconexiontravel.com/?p=156',0,'post','',0);
