INSERT INTO `pcta_posts` VALUES (158,1,'2020-03-13 15:11:56','2020-03-13 15:11:56','[tabby title=\"Itinerario\"]\r\n<h2>Día 1: Cerro Blanco</h2>\r\nNuestro staff se encargará de recogerlo de su respectivo hotel a las 5:00am. de la mañana para dar inicio a este tour, el cual nos conducirá el transporte turístico hasta el kilómetro N° 23, para ascender a la cima haciendo trekking por 3horas aproximadamente con nuestro equipo de tablas, cera para las tablas, especial sunglasses, Snacks, vuestro guía especialista en sandboarding les conducirá por un sendero angosto en forma zigzagueante, realizando paradas cada cierto tramo para tomar un respectivo descanso y observar las cadenas montañosas enmarcadas por una corteza, que son deformaciones naturales a lo largo de millones de años, en el trayecto también observarán canales subterráneos de minas pertenecientes a personas mineros trabajando de una manera informal, explorando minas de oro, cobre, plata; antes de llegar a la cima su guía realizará un pequeño ritual al cerro (Dios Apu), costumbre ancestral para poder ascender con tranquilidad a la duna.\r\n\r\nEn la cima el guía les dará algunas recomendaciones de sacarse los calzados para tomar un buen descanso, relajarse y sentir las energías que tiene ésta inmensa duna. Desde allí se obtiene una hermosa vista panorámica al valle de Nazca, y algunas veces suele ver zorros andinos y cóndores sobrevolando por los alrededores. Después de un pequeño desayuno vuestro guía les enseñará a como practicar Sandboarding iniciando en pequeñas dunas hasta llegar a la última que es la más grande, se deslizarán a gran velocidad sintiendo una adrenalina increíble.\r\n\r\n11:00Am. Finalmente se caminará por unos 30 minutos donde nos recogerá el transporte turístico Que nos llevará hasta su respectivo hotel en la ciudad de Nazca.\r\n\r\n[tabby title=\"Incluyen\"]\r\n<h2>Incluye</h2>\r\n<ul>\r\n 	<li>Recojo de su hotel o estación de bus en Nazca.</li>\r\n 	<li>Transporte</li>\r\n 	<li>Caminata</li>\r\n 	<li>Tablas de sandboarding.</li>\r\n 	<li>Entrada turística.</li>\r\n 	<li>Prácticas de sandboarding.</li>\r\n 	<li>Botella de Agua e Hidratante.</li>\r\n 	<li>Guía profesional de turismo.</li>\r\n 	<li>Asistencia permanente.</li>\r\n</ul>\r\n<h2>No incluye</h2>\r\n<ul>\r\n 	<li>Snack</li>\r\n 	<li>propinas</li>\r\n</ul>\r\n[tabbyending]','Sandboard en la Duna Cerro Blanco','','publish','open','open','','sandboard-en-la-duna-cerro-blanco','','','2023-04-15 22:21:23','2023-04-15 22:21:23','',0,'https://peruconexiontravel.com/?p=158',0,'post','',0);
