INSERT INTO `pcta_posts` VALUES (188,1,'2020-05-04 03:22:53','2020-05-04 03:22:53','[tabby title=\"Itinerario\"]\r\n<h2>Día 1: Paracas - Islas Ballestas - Huacachina</h2>\r\nExcursión a la península de paracas, el santuario de vida silvestre más importante de la costa peruana. Paseo en bote a motor a las islas ballestas, en la reserva nacional de paracas, donde podremos observar leones marinos, pájaros bobos, pelicanos, pingüinos y otras aves marinas. Al regreso tendremos la oportunidad de ver el “candelabro”, una figura gigante del estilo de las líneas de Nazca hecha en la arena. Tiempo libre antes de regresar podrá sacar fotos a los lobos marinos, las focas y aves marinas. Retorno\r\n\r\nTendremos las siguientes vistas: la catedral de la ciudad de Ica, museo Regional, algunas vitivinícolas de la zona y la laguna de la Huacachina en un tradicional lugar de descanso para que los iqueños, la laguna aparece como un oasis en medio del desierto, conformado un esplendido paisaje de dunas y huarangos.\r\n\r\nTraslado al terminal de buses y salida a lima\r\n\r\n[tabby title=\"Incluyen\"]\r\n<h2>Incluye</h2>\r\n<ul>\r\n 	<li>Transporte</li>\r\n 	<li>Entrada a los atractivos</li>\r\n 	<li>Guía profesional bilingüe</li>\r\n 	<li>Bus de Lima – Paracas - Ica (Cruz del Sur)</li>\r\n</ul>\r\n<h2>No incluye</h2>\r\n<ul>\r\n 	<li>Almuerzo</li>\r\n 	<li>Traslados en Lima</li>\r\n</ul>\r\n[tabbyending]','Tour Paracas','','inherit','closed','closed','','162-revision-v1','','','2020-05-04 03:22:53','2020-05-04 03:22:53','',162,'https://peruconexiontravel.com/2020/05/04/162-revision-v1/',0,'revision','',0);
