INSERT INTO `pcta_posts` VALUES (192,1,'2020-05-04 03:25:26','2020-05-04 03:25:26','[tabby title=\"Itinerario\"]\r\n<h2>Día 1: Nazca</h2>\r\nDisfrute de un vuelo excitante sobre las Líneas de Nazca, el cual ofrece una oportunidad espectacular para ver 12 de las mundialmente famosas Líneas de Nazca, incluyendo el colibrí, el perro, las manos, el astronauta, el árbol, la araña, la ballena, la lagartija, el tiburón y mucho más.\r\n\r\nLo recogeremos en su hotel en Nazca o en la estación de bus. Será transportado al Aeropuerto María Reiche, a 10 minutos de distancia del centro de Nazca. En el aeropuerto lo ayudaremos con los procedimientos de registro y entrada, tales como el pago de su impuesto de aeropuerto, pasar por seguridad y el pesaje. Luego podrá ver un breve documental acerca del descubrimiento de las Líneas de Nazca. Después, lo asistiremos en su entrada al aeroplano Cessna 206.\r\n\r\n[tabby title=\"Incluyen\"]\r\n<h2>Incluye</h2>\r\n<ul>\r\n 	<li>Recogida en su hotel o la estación de bus</li>\r\n 	<li>Traslado al aeropuerto</li>\r\n 	<li>Vídeo documental acerca de las Líneas de Nazca</li>\r\n 	<li>Un asiento abordo de una aeronave Cessna</li>\r\n 	<li>Transporte de regreso a su hotel</li>\r\n</ul>\r\n<h2>No incluye</h2>\r\n<ul>\r\n 	<li>Impuesto de aeropuerto ($10 USD por persona)</li>\r\n 	<li>propinas</li>\r\n</ul>\r\n[tabbyending]','Sobrevuelo Líneas de Nazca','','inherit','closed','closed','','160-revision-v1','','','2020-05-04 03:25:26','2020-05-04 03:25:26','',160,'https://peruconexiontravel.com/2020/05/04/160-revision-v1/',0,'revision','',0);
