INSERT INTO `pcta_posts` VALUES (200,1,'2020-05-04 03:31:21','2020-05-04 03:31:21','[tabby title=\"Itinerario\"]\r\n<h2>Día 1: Ica</h2>\r\nHora de inicio del tour: 1:00 p.m.\r\n\r\nPunto de Encuentro: Recojo en hotel o Estación de Buses\r\n\r\nEl tour te permitirá conocer bodegas vitivinícolas artesanales, en las cuales podrás degustar vinos y piscos de gran calidad.\r\n\r\nPartida con Destino a la Huacachina y el centro artesanal. Se darán 2 horas libres, oportunidad para comprar artesanías (libre), o practicar alguna actividad en el desierto como sandboard (no incluido) o paseos en tubulares (no incluido) o realizar paseos en bote por la laguna (no incluido)\r\n\r\nPartida con destino a Cachiche. Conoce la historia de sus brujas y sus antiguas leyendas.\r\n\r\n6:30 p.m. Fin del tour.\r\n\r\n[tabby title=\"Incluyen\"]\r\n<h2>Incluye</h2>\r\n<ul>\r\n 	<li>Recojo en hoteles ubicados en el centro de la ciudad y estación de buses.</li>\r\n 	<li>Degustación de Vinos y Piscos.</li>\r\n 	<li>Visita a Bodegas Vitivinícolas.</li>\r\n 	<li>Paseo por la Ciudad.</li>\r\n 	<li>Visita a la Huacachina.</li>\r\n 	<li>Transporte Turístico.</li>\r\n 	<li>Guía de Turismo.</li>\r\n</ul>\r\n<h2>No incluye</h2>\r\n<ul>\r\n 	<li></li>\r\n 	<li>Paseos en Tubulares.</li>\r\n 	<li>Comidas ni Bebidas.</li>\r\n 	<li>Ningún otro punto no establecido en el tour.</li>\r\n</ul>\r\n[tabbyending]','City Tour Ica','','inherit','closed','closed','','154-revision-v1','','','2020-05-04 03:31:21','2020-05-04 03:31:21','',154,'https://peruconexiontravel.com/2020/05/04/154-revision-v1/',0,'revision','',0);
