INSERT INTO `pcta_posts` VALUES (272,1,'2020-05-04 04:37:51','2020-05-04 04:37:51','[tabby title=\"Itinerario\"]\r\n<h2>Día 1: Cusco - Km. 104 - Wiñayhuayna - Aguas Calientes</h2>\r\nIniciamos con el recojo a su respectivo hotel a las 04:00 am, para dirigirnos en un auto turístico al pueblo de Ollantaytambo con un tiempo de viaje aproximado de 2 horas, lugar donde abordaremos nuestro tren que nos llevara hasta el Km. 104 donde iniciaremos nuestra caminata, después de hacer nuestro registro en el control visitaremos el sitio arqueológico de Chachabamba (2100 msnm), luego continuaremos nuestro recorrido por 4 horas aprox. hasta llegar a Wiñayhuayna (2600 msnm), aquí tendremos un descanso para degustar de nuestro almuerzo (box lunch), después continuamos por 2 horas hasta llegar a Inti Punku o puerta del sol, donde tendremos las primeras vistas de la montaña de Waynapicchu y la ciudad inca, continuamos unos 40 minutos y llegamos a Machupicchu donde tomaremos la foto tradicional. Después abordaremos el bus al pueblo de Aguas calientes para dirigirnos a nuestro hotel y nuestra cena respectivamente.\r\n<h2>Día 2: Aguas Calientes - Machu Picchu - Aguas Calientes - Cusco</h2>\r\nMuy temprano iniciaremos nuestra caminata para dirigirnos a Machupicchu que tomará 1 hora y media de subida aprox. el tour guiado tendrá una duración de 2 horas aprox. donde visitaremos lugares importantes como el templo del Sol, la Casa del Inca entre otros; luego tendrán el tiempo libre para seguir con la visita por su cuenta. Después se dirigirán nuevamente al pueblo de Aguas Calientes para tomar su tren de retorno hasta Ollantaytambo y después tomar un auto turístico hacia la ciudad del Cusco.\r\n\r\n[tabby title=\"Incluyen\"]\r\n<h2>Incluye</h2>\r\n<ul>\r\n 	<li>Transporte</li>\r\n 	<li>Boletos de tren Ollantaytambo - Km 104</li>\r\n 	<li>Boletos de tren Aguas Calientes - Ollantaytambo</li>\r\n 	<li>Boletos de ingreso Camino Inca Machupicchu</li>\r\n 	<li>Guía profesional bilingüe</li>\r\n 	<li>Hotel</li>\r\n 	<li>Alimentación (1 desayuno, 1 almuerzo, 1 cena)</li>\r\n 	<li>Boletos de bus Machupicchu – Aguas Calientes(ida/vuelta)</li>\r\n 	<li>1 noche de hotel</li>\r\n</ul>\r\n<h2>No incluye</h2>\r\n<ul>\r\n 	<li>Almuerzo del ultimo día</li>\r\n 	<li>Visita a las termales en Aguas Calientes</li>\r\n 	<li>Boletos de ingreso a la Montaña Huaynapicchu o a la Montaña Machupicchu</li>\r\n</ul>\r\n[tabbyending]','Camino Inca Machu Picchu','','inherit','closed','closed','','112-revision-v1','','','2020-05-04 04:37:51','2020-05-04 04:37:51','',112,'https://peruconexiontravel.com/2020/05/04/112-revision-v1/',0,'revision','',0);
