INSERT INTO `pcta_posts` VALUES (276,1,'2020-05-04 04:51:15','2020-05-04 04:51:15','[tabby title=\"Itinerario\"]\r\n<h2>Día 1: Cusco - Tipón</h2>\r\nhora de recojo en el hotel a las 08:00 hrs. Para luego desplazarnos hacia el centro arqueológico de Tipón, luego no dirigiremos a la ciudadela pre-inca de Pikillaqta y para luego finalizar el tour en la Iglesia de San Pedro conocida como “La capilla Sixtina de America” ubicado en el distrito de Andahuaylillas.\r\n\r\n[tabby title=\"Incluyen\"]\r\n<h2>Incluye</h2>\r\n<ul>\r\n 	<li>Guía profesional bilingüe</li>\r\n 	<li>Transporte</li>\r\n</ul>\r\n<h2>No incluye</h2>\r\n<ul>\r\n 	<li>Alimentación</li>\r\n 	<li>BTP (boleto turístico parcial)</li>\r\n 	<li>Boleto de ingreso a Andahuaylillas</li>\r\n</ul>\r\n[tabbyending]','Valle Sur Cusco','','inherit','closed','closed','','110-revision-v1','','','2020-05-04 04:51:15','2020-05-04 04:51:15','',110,'https://peruconexiontravel.com/2020/05/04/110-revision-v1/',0,'revision','',0);
INSERT INTO `pcta_posts` VALUES (277,1,'2023-04-15 22:52:32','2023-04-15 22:52:32','[tabby title=\"Itinerario\"]\n<h2>Día 1: Cusco - Pisac</h2>\n<ol>\n 	<li><strong>Pisaq: </strong>hora de recojo en el hotel 08:00 hrs. En cusco Para desplazarnos hacia el centro arqueológico, mercado artesanal nativo de Pisaq. Seguidamente por todo el valle sagrado de los incas apreciando el paisaje y la agricultura.</li>\n</ol>\nA las 12<strong>:</strong>00 tendremos un almuerzo bufet en Urubamba, después del suculento almuerzo, continuamos con el viaje al centro arqueológico de Ollantaytambo, posteriormente nos dirigiremos hacia el pueblo andino de Chinchero.\n\n[tabby title=\"Incluyen\"]\n<h2>Incluye</h2>\n<ul>\n 	<li>Transporte en Bus Turístico</li>\n 	<li>Guía Turístico</li>\n 	<li>Almuerzo Buffet</li>\n</ul>\n<h2>No incluye</h2>\n<ul>\n 	<li>Boleto turístico</li>\n</ul>\n[tabbyending]','Valle Sagrado','','inherit','closed','closed','','108-autosave-v1','','','2023-04-15 22:52:32','2023-04-15 22:52:32','',108,'https://peruconexiontravel.com/2020/05/04/108-autosave-v1/',0,'revision','',0);
