INSERT INTO `pcta_posts` VALUES (439,2,'2020-08-14 02:28:12','2020-08-14 02:28:12','1) TOUR MONTAÑA DE COLORES\r\n\r\n&nbsp;\r\n\r\n-Vinicunca o Winikunka, llamada también Montaña de Siete Colores, Montaña Arcoíris o Montaña de Colores (los pobladores le llaman Cerro Colorado), es una montaña del Perú con una altitud de 5.200 msnm.\r\n\r\n&nbsp;\r\n\r\nEstá situada en el camino al nevado Ausangate, en los Andes del Perú, Región Cusco, entre los distritos de Cusipata, provincia de Quispicanchi, y Pitumarca, provincia de Canchis','TOUR MONTAÑA DE COLORES','','inherit','closed','closed','','435-revision-v1','','','2020-08-14 02:28:12','2020-08-14 02:28:12','',435,'https://peruconexiontravel.com/435-revision-v1',0,'revision','',0);
INSERT INTO `pcta_posts` VALUES (440,2,'2020-08-14 02:54:42','2020-08-14 02:54:42','1).TOUR LAGUNA HUMANTAY\r\n\r\n-LA LAGUNA HUMANTAY SE UBICA A MAS DE 4,200 MSNM ES UNO DE LOS ATRACTIVOS TURISTICOS MAS VISITADOS EN PERÚ. TOUR DE LAGUNA HUMANTAY SE TRATA DE UNO DE LOS PAISAJES DE LOS ANDES DEL PERÚ,LA LAGUNA HUMANTAY SE UVICA SERCA DEL NEVADO SALKANTAY EL LA CORDILLERA DE LOS ANDES DEL CUSCO,PERÚ.','TOUR LAGUNA HUMANTAY','','publish','open','open','','tour-laguna-humantay','','','2023-04-15 21:24:05','2023-04-15 21:24:05','',0,'https://peruconexiontravel.com/?p=440',0,'post','',0);
