INSERT INTO `pcta_posts` VALUES (467,1,'2020-08-15 00:12:54','2020-08-15 00:12:54','TOUR SALKANTAY TREKKING\r\n\r\n-  <a href=\"https://peruconexiontravel.com/\">El Nevado de Salkantay</a>, es uno de las montañas más elevadas de la región del Cusco, junto con el nevado de Ausangate en la cordillera de Vilcanota la cual está situada más al sur.\r\n\r\n&nbsp;\r\n\r\nNo obstante, es considerada la más grandiosa en su espléndido aislamiento y la grandeza de su esplendor . Es además una de las montañas de la región andina que presentan mayores problemas técnicos, en todas sus vertientes, para la escalada deportiva.\r\n\r\nLa cumbre del Salcantay presenta dos cimas, la Este y la OesteAntiguamente la Oeste, más esbelta y atractiva que la Este era ligeramente más elevada al estar coronada por un serac. Tras el paso de los años y el derrumbe de este serac, como constato el prestigioso Pireneista Louis Audoubert, la altura es prácticamente idéntica en ambas cimas.','TOUR A SALKANTAY TREKKING','','inherit','closed','closed','','457-revision-v1','','','2020-08-15 00:12:54','2020-08-15 00:12:54','',457,'https://peruconexiontravel.com/457-revision-v1',0,'revision','',0);
